import { useMemo, useState } from "react";
import SEOHead from "@/components/SEOHead";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import FAQItem from "@/components/FAQItem";
import { formatCurrencyValue, useCurrencyVersion } from "@/lib/currency";

const FAQS = [
  { q: "What is a traditional IRA?", a: "A traditional IRA is an individual retirement account that may allow tax-deductible contributions, with withdrawals generally taxed in retirement." },
  { q: "What are the IRA contribution limits?", a: "IRA limits can change by tax year and may include catch-up contributions for older savers. Check current IRS limits before contributing." },
  { q: "How does a traditional IRA reduce your taxes?", a: "Eligible traditional IRA contributions can reduce taxable income in the contribution year, creating current tax savings." },
  { q: "What is the IRA income limit?", a: "Income limits affect deductibility and Roth eligibility. The rules depend on filing status and workplace retirement plan coverage." },
  { q: "When must you start taking IRA withdrawals?", a: "Traditional IRAs are generally subject to required minimum distributions starting at the IRS-required age." },
];

const money = (v: number, d = 0) => formatCurrencyValue(Number.isFinite(v) ? v : 0, { maximumFractionDigits: d });
const inputClass = "w-full px-3 py-2 rounded-xl border border-input bg-background text-foreground text-lg font-bold focus:outline-none focus:ring-2 focus:ring-primary/40 transition-all";
const grow = (balance: number, annual: number, rate: number, years: number) => Array.from({ length: years }, (_, i) => i).reduce((value) => value * (1 + rate / 100) + annual, balance);

export default function IRACalculator() {
  useCurrencyVersion();
  const [age, setAge] = useState(35);
  const [retirementAge, setRetirementAge] = useState(65);
  const [balance, setBalance] = useState(20000);
  const [contribution, setContribution] = useState(6000);
  const [rate, setRate] = useState(7);
  const [taxRate, setTaxRate] = useState(22);
  const years = Math.max(0, retirementAge - age);
  const result = useMemo(() => {
    const finalBalance = grow(balance, contribution, rate, years);
    const afterTax = finalBalance * (1 - taxRate / 100);
    const taxSavings = contribution * years * (taxRate / 100);
    const monthlyIncome = afterTax * 0.04 / 12;
    const rows = Array.from({ length: Math.min(years, 60) }, (_, i) => {
      const year = i + 1;
      return { age: age + year, balance: grow(balance, contribution, rate, year), afterTax: grow(balance, contribution, rate, year) * (1 - taxRate / 100) };
    });
    return { finalBalance, afterTax, taxSavings, monthlyIncome, rows };
  }, [age, balance, contribution, rate, taxRate, years]);
  const comparison = [1000, 2000, 4000, 6000, 7000].map((amount) => ({ amount, at25: grow(0, amount, 7, 40), at35: grow(0, amount, 7, 30), at45: grow(0, amount, 7, 20), savings: amount * 0.22 }));

  return (
    <>
      <SEOHead title="Free IRA Calculator Online - Calculate Traditional IRA Growth and Retirement Income | CalcHive" description="Free online IRA calculator. Calculate traditional IRA balance at retirement, tax savings and monthly retirement income for any contribution and return rate instantly. 100% free, no signup required." canonical="/ira-calculator" keywords="free IRA calculator, traditional IRA calculator free online, IRA growth calculator free, calculate IRA returns free, IRA contribution calculator free" category="Financial Calculators" breadcrumbName="Free IRA Calculator Online" schemaType="WebApplication" schemaApplicationCategory="CalculatorApplication" faqs={FAQS} />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10">
        <div className="mb-8"><span className="text-xs font-semibold uppercase tracking-widest text-sky-600 dark:text-sky-400 bg-sky-50 dark:bg-sky-950/50 px-3 py-1 rounded-full mb-4 inline-block">Financial</span><h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free IRA Calculator Online</h1><p className="text-muted-foreground leading-relaxed">Estimate traditional IRA growth, after-tax value, tax savings, and retirement income.</p></div>
        <AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8">
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 mb-8">
            <div><label className="text-sm font-semibold text-foreground block mb-2">Current age</label><input type="number" value={age} onChange={(e) => setAge(Number(e.target.value))} className={inputClass} /></div>
            <div><label className="text-sm font-semibold text-foreground block mb-2">Retirement age</label><input type="number" value={retirementAge} onChange={(e) => setRetirementAge(Number(e.target.value))} className={inputClass} /></div>
            <div><label className="text-sm font-semibold text-foreground block mb-2">Current IRA balance</label><input type="number" value={balance} onChange={(e) => setBalance(Number(e.target.value))} className={inputClass} /></div>
            <div><label className="text-sm font-semibold text-foreground block mb-2">Annual contribution</label><input type="number" value={contribution} onChange={(e) => setContribution(Number(e.target.value))} className={inputClass} /></div>
            <div><label className="text-sm font-semibold text-foreground block mb-2">Expected return (%)</label><input type="number" value={rate} onChange={(e) => setRate(Number(e.target.value))} className={inputClass} /></div>
            <div><label className="text-sm font-semibold text-foreground block mb-2">Tax rate (%)</label><input type="number" value={taxRate} onChange={(e) => setTaxRate(Number(e.target.value))} className={inputClass} /></div>
          </div>
          <div className="bg-gradient-to-br from-sky-500 to-sky-700 rounded-2xl p-6 text-center shadow-lg"><p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">Traditional IRA Balance at Retirement</p><p className="text-5xl sm:text-6xl font-black text-white">{money(result.finalBalance)}</p></div>
          <div className="grid grid-cols-1 sm:grid-cols-3 gap-3 mt-4"><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">After-tax value</p><p className="text-lg font-extrabold text-foreground">{money(result.afterTax)}</p></div><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">Tax savings</p><p className="text-lg font-extrabold text-foreground">{money(result.taxSavings)}</p></div><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">Monthly income</p><p className="text-lg font-extrabold text-foreground">{money(result.monthlyIncome)}</p></div></div>
        </section>
        <ShareButton />
        <section className="mb-8 space-y-6">
          <h2 className="text-2xl font-bold text-foreground">How to Calculate Traditional IRA Growth and Tax Savings for Free</h2><p className="text-muted-foreground leading-relaxed">This traditional IRA calculator grows your balance and contributions until retirement, then estimates after-tax retirement value.</p>
          <h2 className="text-2xl font-bold text-foreground">How IRA Contributions Reduce Your Taxable Income</h2>
          <div className="overflow-x-auto"><table className="w-full text-sm border border-border rounded-xl overflow-hidden"><caption className="caption-top text-left font-bold text-foreground mb-3">Traditional IRA Growth by Annual Contribution at 7% Return</caption><thead className="bg-muted/60"><tr>{["Annual Contribution", "Starting at 25", "Starting at 35", "Starting at 45", "Tax Savings at 22% Rate"].map((h) => <th key={h} className="text-left py-3 px-3 font-semibold text-foreground">{h}</th>)}</tr></thead><tbody className="divide-y divide-border">{comparison.map((row) => <tr key={row.amount}><td className="py-2.5 px-3 font-semibold">{money(row.amount)}</td><td className="py-2.5 px-3">{money(row.at25)}</td><td className="py-2.5 px-3">{money(row.at35)}</td><td className="py-2.5 px-3">{money(row.at45)}</td><td className="py-2.5 px-3">{money(row.savings)}</td></tr>)}</tbody></table></div>
          <h2 className="text-2xl font-bold text-foreground">Free Traditional IRA Retirement Planning Tool for Everyone</h2>
          <div className="overflow-x-auto"><table className="w-full text-sm border border-border rounded-xl overflow-hidden"><caption className="caption-top text-left font-bold text-foreground mb-3">Growth Table</caption><thead className="bg-muted/60"><tr>{["Age", "Projected Balance", "After-Tax Value"].map((h) => <th key={h} className="text-left py-3 px-3 font-semibold text-foreground">{h}</th>)}</tr></thead><tbody className="divide-y divide-border">{result.rows.map((row) => <tr key={row.age}><td className="py-2.5 px-3">{row.age}</td><td className="py-2.5 px-3">{money(row.balance)}</td><td className="py-2.5 px-3">{money(row.afterTax)}</td></tr>)}</tbody></table></div>
        </section>
        <section className="mb-8"><h3 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h3><div className="space-y-3">{FAQS.map((faq) => <FAQItem key={faq.q} q={faq.q} a={faq.a} />)}</div></section>
        <AdPlaceholder size="rectangle" className="mx-auto mb-8" /><RelatedTools exclude="/ira-calculator" headingLevel="h3" />
      </main>
    </>
  );
}


